#include <iostream>
#include <vector>
#include <string>
#include <cstring> // For strcpy, strcmp, strlen

// Assume countWords function is defined elsewhere (e.g., in the submitted code)
extern int countWords(char* str);

struct TestCase {
    std::string input_str;
    std::string expected;
};

int main() {
    std::vector<TestCase> tests = {
        { "hello world", "2" },
        { "programming", "1" },
        { "", "0" },
        { "one two three four", "4" },
        { "singleword", "1" },
        { "nullptr", "0" }
    };

    for (size_t i = 0; i < tests.size(); ++i) {
        const TestCase& tc = tests[i];

        std::cout << "Test Case " << (i + 1) << ": Input: ";
        if (tc.input_str == "nullptr") {
            std::cout << "nullptr";
            // For nullptr, the function correctly returns 0 in this version.
            std::cout << ", Expected: " << tc.expected << ", Actual: " << countWords(nullptr) << std::endl;
        } else {
            // Create a mutable copy of the input string for countWords
            // This is important because strtok modifies the input string.
            char buffer[256]; // Assuming max string length 255 + null terminator
            if (tc.input_str.length() >= sizeof(buffer)) {
                std::cerr << "Error: Input string \"" << tc.input_str << "\" too long for buffer in test driver." << std::endl;
                continue;
            }
            strcpy(buffer, tc.input_str.c_str());

            std::cout << '"' << tc.input_str << '"';
            int actual_output = countWords(buffer);
            std::cout << ", Expected: " << tc.expected << ", Actual: " << actual_output << std::endl;
        }
    }
    return 0;
}
